import React from 'react';
import { NotificationProvider, useNotifications } from './NotificationSystem';
import './styles.css';

function Demo() {
  const { notifications, addNotification, dismiss, dismissAll } = useNotifications();

  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif' }}>
      <h1 style={{ marginBottom: '1rem' }}>Notifications</h1>
      <div className="notif-actions">
        <button data-testid="add-info" onClick={() => addNotification('New message received', 'info')}>Add Info</button>
        <button data-testid="add-success" onClick={() => addNotification('Operation successful!', 'success')}>Add Success</button>
        <button data-testid="add-error" onClick={() => addNotification('Something went wrong', 'error', 5000)}>Add Error</button>
        <button data-testid="dismiss-all" onClick={dismissAll}>Dismiss All</button>
      </div>
      <p data-testid="count" className="notif-count">{notifications.length} notification(s)</p>
      <div className="notif-stack">
        {notifications.map(n => (
          <div key={n.id} data-testid={`notification-${n.id}`} className={`notif notif--${n.type}`}>
            <span>{n.message}</span>
            <button data-testid={`dismiss-${n.id}`} className="notif__close" onClick={() => dismiss(n.id)}>✕</button>
          </div>
        ))}
      </div>
    </div>
  );
}

export default function App() {
  return (
    <NotificationProvider>
      <Demo />
    </NotificationProvider>
  );
}

import React, { createContext, useContext, useReducer, useCallback, useEffect, useRef } from 'react';

// --- Types ---
export interface Notification {
  id: number;
  message: string;
  type: 'info' | 'success' | 'error';
  duration: number;
}

type NotifAction =
  | { type: 'ADD'; notification: Notification }
  | { type: 'DISMISS'; id: number }
  | { type: 'DISMISS_ALL' };

const MAX_NOTIFICATIONS = 5;
let nextNotifId = 1;

// --- Reducer ---
export function notificationReducer(state: Notification[], action: NotifAction): Notification[] {
  switch (action.type) {
    case 'ADD':
      // TODO: Add notification, enforce MAX limit
      return state;
    case 'DISMISS':
      // TODO: Remove by id
      return state;
    case 'DISMISS_ALL':
      // TODO: Clear all
      return state;
    default:
      return state;
  }
}

// --- Context ---
interface NotifContextType {
  notifications: Notification[];
  addNotification: (message: string, type: Notification['type'], duration?: number) => void;
  dismiss: (id: number) => void;
  dismissAll: () => void;
}

const NotifContext = createContext<NotifContextType | null>(null);

// --- Provider ---
export const NotificationProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [notifications, dispatch] = useReducer(notificationReducer, []);
  // TODO: Set up auto-dismiss with useEffect
  // TODO: Track timeout IDs in a ref for cleanup

  const addNotification = useCallback((message: string, type: Notification['type'], duration = 3000) => {
    const id = nextNotifId++;
    dispatch({ type: 'ADD', notification: { id, message, type, duration } });
  }, []);

  const dismiss = useCallback((id: number) => {
    dispatch({ type: 'DISMISS', id });
  }, []);

  const dismissAll = useCallback(() => {
    dispatch({ type: 'DISMISS_ALL' });
  }, []);

  return (
    <NotifContext.Provider value={{ notifications, addNotification, dismiss, dismissAll }}>
      {children}
    </NotifContext.Provider>
  );
};

// --- Hook ---
export function useNotifications(): NotifContextType {
  const ctx = useContext(NotifContext);
  if (!ctx) throw new Error('useNotifications must be used within NotificationProvider');
  return ctx;
}

.notif-actions {
  display: flex;
  gap: 0.5rem;
  margin-bottom: 1rem;
}

.notif-actions button {
  padding: 0.5rem 1rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  background: #f9fafb;
  cursor: pointer;
  font-size: 0.875rem;
}

.notif-count {
  font-size: 0.8125rem;
  color: #6b7280;
  margin-bottom: 0.75rem;
}

.notif-stack {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  max-width: 24rem;
}

.notif {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 0.75rem 1rem;
  border-radius: 0.375rem;
  font-size: 0.875rem;
  animation: notif-in 0.2s ease;
}

@keyframes notif-in {
  from { opacity: 0; transform: translateY(-0.5rem); }
  to { opacity: 1; transform: translateY(0); }
}

.notif--info {
  background: #eff6ff;
  border: 1px solid #bfdbfe;
  color: #1e40af;
}

.notif--success {
  background: #f0fdf4;
  border: 1px solid #bbf7d0;
  color: #166534;
}

.notif--error {
  background: #fef2f2;
  border: 1px solid #fecaca;
  color: #991b1b;
}

.notif__close {
  background: none;
  border: none;
  cursor: pointer;
  font-size: 0.875rem;
  color: inherit;
  opacity: 0.6;
}

.notif__close:hover {
  opacity: 1;
}

