import { render, screen, fireEvent, act } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import { notificationReducer } from './NotificationSystem';

const mkNotif = (id: number, type: 'info' | 'success' | 'error' = 'info') => ({
  id, message: `Msg ${id}`, type, duration: 3000,
});

describe('notificationReducer', () => {
  it('adds a notification', () => {
    const result = notificationReducer([], { type: 'ADD', notification: mkNotif(1) });
    expect(result).toHaveLength(1);
    expect(result[0].id).toBe(1);
  });

  it('enforces max 5 notifications', () => {
    let state = [mkNotif(1), mkNotif(2), mkNotif(3), mkNotif(4), mkNotif(5)];
    state = notificationReducer(state, { type: 'ADD', notification: mkNotif(6) });
    expect(state).toHaveLength(5);
    expect(state.find(n => n.id === 1)).toBeUndefined();
    expect(state.find(n => n.id === 6)).toBeDefined();
  });

  it('dismisses by id', () => {
    const state = [mkNotif(1), mkNotif(2)];
    const result = notificationReducer(state, { type: 'DISMISS', id: 1 });
    expect(result).toHaveLength(1);
    expect(result[0].id).toBe(2);
  });

  it('dismisses all', () => {
    const state = [mkNotif(1), mkNotif(2), mkNotif(3)];
    const result = notificationReducer(state, { type: 'DISMISS_ALL' });
    expect(result).toHaveLength(0);
  });
});

describe('NotificationSystem integration', () => {
  beforeEach(() => {
    jest.useFakeTimers();
  });
  afterEach(() => {
    jest.useRealTimers();
  });

  it('adds and displays notifications', () => {
    const { NotificationProvider, useNotifications } = require('./NotificationSystem');
    function Demo() {
      const { notifications, addNotification } = useNotifications();
      return (
        <div>
          <button data-testid="add" onClick={() => addNotification('Test', 'info')}>Add</button>
          <span data-testid="count">{notifications.length}</span>
        </div>
      );
    }
    render(<NotificationProvider><Demo /></NotificationProvider>);
    fireEvent.click(screen.getByTestId('add'));
    expect(screen.getByTestId('count')).toHaveTextContent('1');
  });

  it('auto-dismisses after duration', () => {
    const { NotificationProvider, useNotifications } = require('./NotificationSystem');
    function Demo() {
      const { notifications, addNotification } = useNotifications();
      return (
        <div>
          <button data-testid="add" onClick={() => addNotification('Test', 'info', 1000)}>Add</button>
          <span data-testid="count">{notifications.length}</span>
        </div>
      );
    }
    render(<NotificationProvider><Demo /></NotificationProvider>);
    fireEvent.click(screen.getByTestId('add'));
    expect(screen.getByTestId('count')).toHaveTextContent('1');
    act(() => { jest.advanceTimersByTime(1000); });
    expect(screen.getByTestId('count')).toHaveTextContent('0');
  });
});

